INSERT INTO "PUBLIC"."IDEA" VALUES
(1, 'AI', TIMESTAMP '2026-03-11 15:24:47.25257', 'CHECK OUR RESUME ', NULL, 'Students and job seekers', NULL, 'AI POWERED RESUME CHECKER', 151, 10, NULL, NULL),
(3, 'AI', TIMESTAMP '2026-03-11 21:21:46.810206', 'Students don''t know which career suits them.', NULL, 'College, students', 'AI analyzes skills and suggests career paths.', 'AI career Mentor', 75, 2, NULL, NULL),
(4, 'SMART CITY', TIMESTAMP '2026-03-12 21:42:20.51395', 'Cities struggle with inefficient garbage collection leading to overflowing bins and poor sanitation.', NULL, 'Municipal Corporations, Smart Cities', 'IoT Sensors, React, Spring Boot, GPS APIs', 'Smart Waste Management System', 37, 3, 'Guest User', 'Install IoT sensors in bins that detect fill levels and notify waste collectors using a centralized dashboard with optimized routes.'),
(5, 'AI', TIMESTAMP '2026-03-13 14:21:29.717968', 'Students don''t know how to build startups', NULL, 'students', 'MERN Stack , APIs', 'AI Startup Mentor', 22, 2, 'Guest User', 'AI suggests startup ideas and mentors'),
(6, 'FINTECH', TIMESTAMP '2026-03-14 01:10:58.980313', 'Many people struggle to manage their personal finances effectively. They often overspend, fail to save regularly, and lack insights into where their money goes. Traditional budgeting apps require manual input and do not provide intelligent recommendations.', NULL, 'Young professionals  College students  Families managing household budgets  Individuals starting their financial journey', 'React, Spring Boot, MySQL, Open Banking APIs, AI/ML models for financial insights', 'AI Personal Finance Advisor', 22, 2, 'Bhavana', 'Develop an AI-powered personal finance assistant that automatically tracks expenses, categorizes spending, and provides personalized financial advice. The system can analyze spending patterns and suggest ways to save money, optimize investments, and manage monthly budgets.'),
(7, 'AI', TIMESTAMP '2026-03-14 14:29:19.954489', 'A platform where microservices and dependencies are tested and managed.', NULL, 'Developers,Engineers', 'react,springboot,groq', 'TraceGraph-AI', 12, 2, 'dhruva@gamil.com', 'a ai powered tool where data is in the form of json formats and output is ai ready explanation'),
(8, 'AI', TIMESTAMP '2026-03-15 20:20:57.344371', 'Students struggle to manage study schedules', NULL, 'Students', 'React,Spring Boot,AI', 'AI Study Planner', 6, 1, 'test', 'AI tool that generates study plans'),
(9, 'AI', TIMESTAMP '2026-04-02 11:20:27.609166', 'Students today face high levels of stress, anxiety, and burnout due to academic pressure, social expectations, and excessive screen time. However, most mental health solutions are either expensive, not personalized, or not engaging enough for daily use.', NULL, U&'Students, early professionals, and remote workers aged 16\201330', 'React, Node.js, MongoDB, TensorFlow Lite, Web Speech API, OpenAI API, IoT integrations', U&'MindSync \2013 AI-Powered Mental Health Companion for Students', 4, 1, 'Sanjana', U&'MindSync is an AI-powered mental wellness platform that monitors user behavior (screen time, typing speed, activity patterns) and detects early signs of stress. It provides real-time interventions like:\000a\000aPersonalized break suggestions\000aAI-generated calming exercises (breathing, journaling prompts)\000aMood tracking using simple check-ins\000aVoice-based emotional support chatbot\000aIntegration with ambient devices (lights/music) for relaxation\000a\000aThe system uses lightweight AI models to ensure privacy and real-time responsiveness.');       
